BEGIN; WITH stale_note_1 AS (SELECT dp.id, prev.note AS fresh_note, prev.note_edited_at AS fresh_edited_at FROM public.delivery_plans dp JOIN LATERAL (SELECT p.note, p.note_edited_at FROM public.delivery_plans p WHERE p.deleted_at IS NULL AND p.product_id = dp.product_id AND public.delivery_point_key(p.customer_id, p.delivery_customer_id) = public.delivery_point_key(dp.customer_id, dp.delivery_customer_id) AND p.plan_date < dp.plan_date AND p.note_edited_at IS NOT NULL ORDER BY p.plan_date DESC, p.note_edited_at DESC NULLS LAST, p.updated_at DESC NULLS LAST, p.created_at DESC NULLS LAST LIMIT 1) prev ON true WHERE dp.deleted_at IS NULL AND dp.plan_date >= DATE '2026-06-01' AND dp.note_edited_at IS NOT NULL AND dp.note_edited_at < prev.note_edited_at AND dp.note IS DISTINCT FROM prev.note), stale_note_2 AS (SELECT dp.id, prev.note_2 AS fresh_note_2, prev.note_2_edited_at AS fresh_edited_at_2 FROM public.delivery_plans dp JOIN LATERAL (SELECT p.note_2, p.note_2_edited_at FROM public.delivery_plans p WHERE p.deleted_at IS NULL AND p.product_id = dp.product_id AND public.delivery_point_key(p.customer_id, p.delivery_customer_id) = public.delivery_point_key(dp.customer_id, dp.delivery_customer_id) AND p.plan_date < dp.plan_date AND p.note_2_edited_at IS NOT NULL ORDER BY p.plan_date DESC, p.note_2_edited_at DESC NULLS LAST, p.updated_at DESC NULLS LAST, p.created_at DESC NULLS LAST LIMIT 1) prev ON true WHERE dp.deleted_at IS NULL AND dp.plan_date >= DATE '2026-06-01' AND dp.note_2_edited_at IS NOT NULL AND dp.note_2_edited_at < prev.note_2_edited_at AND dp.note_2 IS DISTINCT FROM prev.note_2), updated_note_1 AS (UPDATE public.delivery_plans dp SET note = s.fresh_note, note_edited_at = s.fresh_edited_at, updated_at = now(), updated_by = auth.uid() FROM stale_note_1 s WHERE dp.id = s.id RETURNING dp.id), updated_note_2 AS (UPDATE public.delivery_plans dp SET note_2 = s.fresh_note_2, note_2_edited_at = s.fresh_edited_at_2, updated_at = now(), updated_by = auth.uid() FROM stale_note_2 s WHERE dp.id = s.id RETURNING dp.id) SELECT (SELECT count(*) FROM updated_note_1) AS note_1_rows_fixed, (SELECT count(*) FROM updated_note_2) AS note_2_rows_fixed; COMMIT;
